// Gerar URLs de busca otimizadas: 2 queries OR × até 4 páginas = 8 URLs
// Em produção, páginas extras (sem dados) retornam items=[] e são ignoradas

const PAGE_SIZE = 500;

const q1 = 'computador OR microcomputador OR notebook OR tablet OR chromebook OR desktop OR GED OR microfilmagem OR digitalizacao OR microfilme OR escanerizacao OR indexacao';
const q2 = '"ar-condicionado" OR "estacao de trabalho" OR "gestao de documentos" OR "gestao documental" OR "licenciamento de softwares" OR "licenciamento Microsoft"';

const searches = [];
for (const q of [q1, q2]) {
  for (let page = 1; page <= 4; page++) {
    const encoded = encodeURIComponent(q);
    searches.push({
      json: {
        query_group: q === q1 ? 1 : 2,
        page: page,
        url: `https://pncp.gov.br/api/search/?q=${encoded}&tipos_documento=edital&ordenacao=-data&pagina=${page}&tam_pagina=${PAGE_SIZE}&status=recebendo_proposta`
      }
    });
  }
}

return searches;

// ============================================================
// PNCP Monitor v3 — Filtrar, Deduplicar, Preparar dados
// Retorna: editais filtrados + SQL values + HTML email
// ============================================================

const TARGET_UFS = new Set(['RJ', 'SP', 'MG', 'BA', 'PE', 'DF']);
const UF_ORDER = ['RJ', 'SP', 'MG', 'BA', 'PE', 'DF'];

const KEYWORDS = {
  equipamentos_ti: [
    'computador', 'microcomputador', 'notebook', 'tablet',
    'chromebook', 'desktop', 'estação de trabalho', 'estacao de trabalho',
  ],
  gestao_documental: [
    'ged', 'microfilmagem', 'microfilme', 'digitalização', 'digitalizacao',
    'escanerização', 'escanerizacao', 'indexação', 'indexacao',
    'gestão de documentos', 'gestao de documentos',
    'gestão documental', 'gestao documental',
  ],
  software: [
    'licenciamento microsoft', 'licenciamento de softwares',
    'licenciamento de software',
  ],
  climatizacao: [
    'ar-condicionado', 'ar condicionado',
  ],
};

const CATEGORY_LABELS = {
  equipamentos_ti: '💻 Equipamentos de TI',
  gestao_documental: '📄 Gestão Documental',
  software: '🔑 Licenciamento de Software',
  climatizacao: '❄️ Climatização',
};
const CATEGORY_COLORS = {
  equipamentos_ti: '#2980b9',
  gestao_documental: '#8e44ad',
  software: '#27ae60',
  climatizacao: '#e67e22',
};

// Portal base URL for email links
const PORTAL_BASE = 'https://platform.sunyataconsulting.com';

// --- 1. Collect + dedup + filter UF ---
const allResponses = $input.all();
let totalBruto = 0;
let erros = 0;
const seen = new Map();

for (const response of allResponses) {
  const data = response.json;
  const items = data.items || [];
  totalBruto += items.length;
  if (!items.length && data.total === undefined) { erros++; continue; }
  for (const item of items) {
    const ctrl = item.numero_controle_pncp || '';
    const uf = item.uf || '';
    if (ctrl && !seen.has(ctrl) && TARGET_UFS.has(uf)) {
      seen.set(ctrl, item);
    }
  }
}
const uniqueItems = Array.from(seen.values());

// --- 2. Filter by keyword in description ---
function matchKeywords(desc) {
  const lower = desc.toLowerCase();
  const cats = [];
  const kws = [];
  for (const [cat, kwList] of Object.entries(KEYWORDS)) {
    for (const kw of kwList) {
      if (lower.includes(kw.toLowerCase())) {
        cats.push(cat);
        kws.push(kw);
        break;
      }
    }
  }
  return { cats, kws };
}

const editais = [];
for (const item of uniqueItems) {
  const desc = item.description || '';
  const { cats, kws } = matchKeywords(desc);
  if (!cats.length) continue;

  const urlParts = (item.item_url || '').split('/');
  const cnpj = urlParts[2] || '';
  const ano = urlParts[3] || '';
  const seq = urlParts[4] || '';

  editais.push({
    pncp_id: item.numero_controle_pncp || '',
    numero: (item.title || '').replace(/^Edital\s+n[ºo°]\s*/i, '').trim() || null,
    titulo: item.title || '',
    objeto: desc.substring(0, 2000),
    orgao: item.orgao_nome || '',
    orgao_cnpj: item.orgao_cnpj || '',
    uf: item.uf || '',
    municipio: item.municipio_nome || '',
    modalidade: item.modalidade_licitacao_nome || '',
    valor_estimado: item.valor_global || null,
    data_abertura: item.data_inicio_vigencia || item.data_publicacao_pncp || null,
    data_encerramento: item.data_fim_vigencia || null,
    url_pncp: `https://pncp.gov.br/app/editais${(item.item_url || '').replace(/^\/compras/, '')}`,
    keywords_matched: kws,
    categories: cats,
    cnpj_orgao: cnpj,
    ano_compra: ano,
    seq_compra: seq,
    raw_data: item,
  });
}

editais.sort((a, b) => (a.data_encerramento || '9999').localeCompare(b.data_encerramento || '9999'));

