  const jsonb = (o) => o ? `'${JSON.stringify(o).replace(/'/g, "''")}'::jsonb` : 'NULL';
  const num = (n) => n !== null && n !== undefined ? Number(n) : 'NULL';
  const ts = (s) => s ? `'${esc(s)}'::timestamptz` : 'NULL';
  const txt = (s) => s ? `'${esc(s)}'` : 'NULL';

  return `(${txt(e.pncp_id)}, ${txt(e.numero)}, ${txt(e.titulo)}, ${txt(e.objeto)}, ${txt(e.orgao)}, ${txt(e.orgao_cnpj)}, ${txt(e.uf)}, ${txt(e.municipio)}, ${txt(e.modalidade)}, ${num(e.valor_estimado)}, ${ts(e.data_abertura)}, ${ts(e.data_encerramento)}, ${txt(e.url_pncp)}, 'aberto', ${arr(e.keywords_matched)}, ${jsonb(e.raw_data)})`;
});

