  } catch(e) { return iso.substring(0,16); }
}
function diasAte(iso) {
  if (!iso) return 999;
  try { return Math.ceil((new Date(iso) - new Date()) / 86400000); }
  catch(e) { return 999; }
}
function fmtValor(val) {
  if (val === null || val === undefined) return '<em>N/I</em>';
  const n = Number(val);
  if (n === 0) return '<em>Sigiloso</em>';
  return 'R$ ' + n.toLocaleString('pt-BR', {minimumFractionDigits:2, maximumFractionDigits:2});
}

