function fmtValor(val) {
  if (val === null || val === undefined) return '<em>N/I</em>';
  const n = Number(val);
  if (n === 0) return '<em>Sigiloso</em>';
  return 'R$ ' + n.toLocaleString('pt-BR', {minimumFractionDigits:2, maximumFractionDigits:2});
}

const hoje = fmtDate(new Date().toISOString()).split(' ')[0];
const byUF = {};
for (const e of editais) { if (!byUF[e.uf]) byUF[e.uf] = []; byUF[e.uf].push(e); }
const catCounts = {};
for (const e of editais) { for (const c of e.categories) { catCounts[c] = (catCounts[c]||0) + 1; } }
const urgentes = editais.filter(e => diasAte(e.data_encerramento) <= 7).length;

let html = `<!DOCTYPE html><html><head><meta charset="utf-8"></head><body style="margin:0;padding:0;background:#f4f5f7;font-family:'Segoe UI',Arial,sans-serif"><div style="max-width:960px;margin:0 auto;padding:20px">`;

// Header
html += `<div style="background:linear-gradient(135deg,#1a2a3a,#2c3e50);color:#fff;padding:24px 28px;border-radius:10px 10px 0 0">`;
html += `<h1 style="margin:0;font-size:22px">📋 Monitoramento PNCP — ${hoje}</h1>`;
html += `<p style="margin:8px 0 0;font-size:14px;opacity:.85">${editais.length} editais relevantes • ${Object.keys(byUF).length} UFs • ${urgentes} urgente(s)</p>`;
html += `<div style="margin-top:12px">`;
for (const [cat, count] of Object.entries(catCounts).sort((a,b) => b[1]-a[1])) {
  html += `<span style="display:inline-block;background:${CATEGORY_COLORS[cat]||'#95a5a6'};color:#fff;padding:3px 10px;border-radius:12px;font-size:11px;margin:2px">${CATEGORY_LABELS[cat]||cat}: ${count}</span> `;
}
html += `</div></div>`;

// Stats
html += `<div style="background:#fff;border:1px solid #e0e0e0;border-top:none;padding:12px 28px;font-size:12px;color:#666">`;
html += `Buscas: ${allResponses.length} • Bruto: ${totalBruto} • Dedup+UF: ${uniqueItems.length} • Relevantes: ${editais.length} • Ruído: ${uniqueItems.length - editais.length}`;
html += `</div>`;



// Body - by UF
html += `<div style="background:#fff;padding:20px 28px;border:1px solid #e0e0e0;border-top:none;border-radius:0 0 10px 10px">`;

for (const uf of UF_ORDER) {
  const items = byUF[uf];
  if (!items || !items.length) continue;
  const urg = items.filter(i => diasAte(i.data_encerramento) <= 7).length;

  html += `<h2 style="color:#2c3e50;border-bottom:3px solid #3498db;padding-bottom:8px;margin-top:28px">📍 ${uf} — ${items.length} editai${items.length!==1?'s':'l'}`;
  if (urg) html += ` <span style="background:#e74c3c;color:#fff;padding:2px 8px;border-radius:10px;font-size:11px;margin-left:8px">⚠ ${urg} urgente(s)</span>`;
  html += `</h2>`;

  html += `<table border="0" cellpadding="8" cellspacing="0" style="border-collapse:collapse;width:100%;font-size:12px;margin-bottom:10px">`;
  html += `<tr style="background:#34495e;color:#fff"><th style="text-align:left;width:18%">Órgão</th><th style="text-align:left;width:28%">Objeto</th><th style="text-align:center;width:10%">Categoria</th><th style="text-align:center;width:12%">Encerramento</th><th style="text-align:right;width:10%">Valor</th><th style="text-align:center;width:22%">Ações</th></tr>`;

  for (let i = 0; i < items.length; i++) {
    const item = items[i];
    const dias = diasAte(item.data_encerramento);
    const bg = i%2===0 ? '#fff' : '#f8f9fa';
    const brd = dias<=3 ? 'border-left:4px solid #e74c3c' : dias<=7 ? 'border-left:4px solid #f39c12' : 'border-left:4px solid transparent';
    const ds = dias<=3 ? 'color:#e74c3c;font-weight:bold' : dias<=7 ? 'color:#f39c12;font-weight:bold' : '';
    const dl = dias<=0 ? '(ENCERRADO)' : dias===1 ? '(amanhã!)' : dias<=7 ? `(${dias} dias)` : '';

    let catBadges = '';
    for (const cat of item.categories) {
      const parts = (CATEGORY_LABELS[cat]||cat).split(' ');
      catBadges += `<span style="display:inline-block;background:${CATEGORY_COLORS[cat]||'#95a5a6'};color:#fff;padding:1px 6px;border-radius:8px;font-size:9px;margin:1px">${parts[0]} ${parts.slice(1).join(' ')}</span> `;
    }

    const descShort = item.objeto.substring(0,160) + (item.objeto.length>160 ? '...' : '');
    // Links point to portal, not directly to PNCP
    // Use pncp_id for lookup — portal resolves to DB id
    const portalLink = `${PORTAL_BASE}/edital.php?pncp_id=${encodeURIComponent(item.pncp_id)}`;

    html += `<tr style="background:${bg};${brd}">`;
    html += `<td style="padding:8px;vertical-align:top"><strong>${item.orgao}</strong><br/><small style="color:#777">${item.municipio}/${item.uf}</small></td>`;
    html += `<td style="padding:8px;vertical-align:top"><small style="color:#555">${descShort}</small></td>`;
    html += `<td style="padding:8px;text-align:center;vertical-align:top">${catBadges}</td>`;
    html += `<td style="padding:8px;text-align:center;vertical-align:top;${ds}">${fmtDate(item.data_encerramento)}<br/><small>${dl}</small></td>`;
    html += `<td style="padding:8px;text-align:right;vertical-align:top">${fmtValor(item.valor_estimado)}</td>`;
    html += `<td style="padding:8px;text-align:center;vertical-align:top">`;
    html += `<a href="${portalLink}" style="display:inline-block;background:#2980b9;color:#fff;padding:5px 12px;border-radius:4px;text-decoration:none;font-size:10px;margin:2px">📋 Detalhes</a>`;
    html += `<br/><a href="${item.url_pncp}" style="color:#999;font-size:9px;text-decoration:underline;margin-top:4px;display:inline-block">Ver no PNCP ↗</a>`;
    html += `</td></tr>`;
  }
  html += `</table>`;
}

// Footer
html += `<hr style="margin-top:30px;border:none;border-top:1px solid #dee2e6"/>`;
html += `<p style="font-size:10px;color:#999;margin-top:15px">Gerado por <strong>Sunyata Consulting</strong> — IATR Monitoramento PNCP v3.0<br/>${new Date().toISOString()} • ${allResponses.length} buscas • ${erros} erros API</p>`;
html += `</div></div></body></html>`;

// --- 5. Return everything ---
return [{ json: {
  success: true,
  editais_count: editais.length,
  stats: {
    total_buscas: allResponses.length,
    total_bruto: totalBruto,
    total_dedup_uf: uniqueItems.length,
    total_relevante: editais.length,
    ruido: uniqueItems.length - editais.length,
    erros_api: erros,
    por_uf: Object.fromEntries(Object.entries(byUF).map(([k,v]) => [k, v.length])),
    por_categoria: catCounts,
    urgentes: urgentes,
  },
  upsert_sql: upsertSql,
  email: {
    to: 'claudesunyata@gmail.com,filipe.litaiff@ifrj.edu.br,comercial06@iatr.com.br,comercial@iatr.com.br',
    subject: `[PNCP Monitor] ${editais.length} editais relevantes — ${hoje}`,
    html: html
  },
  timestamp: new Date().toISOString()
}}];

// Pass through data, remove large SQL from downstream
const data = $('Filter Format SQL').first().json;

return [{ json: {
  success: data.success,
  editais_count: data.editais_count,
  stats: data.stats,
  email: data.email,
  db_status: 'upsert_complete',
  timestamp: data.timestamp
}}];
